import { Worker } from "../../../backend/src/entities/worker"
import { useState, useEffect } from "react";
import { getWorkers, assignWorker } from "../api";

export default function AssignWorkerForm() {
    const [workers, setWorkers] = useState<Worker[]>([]);
    
    useEffect(() => {
        getWorkers()
        .then((data) => {
            setWorkers(data);
        })
    }, []);

    return (
        <div className="Workers">
                <h2>Trabajadores</h2>
                { workers.length === 0 ? (
                    <h3>No hay trabajadores</h3>
                ) : (
                    workers.map((worker) => (
                        <div className="AssignInfo" key={worker.id}>
                            <p>{worker.name} - {worker.role}</p>
                            <p>{worker.seniority}</p>
                        </div>
                    ))
                )}
        </div>
    )
}
